'use strict';

function renderTable(rows, options = {}) {
  if (rows.length === 0) {
    return '';
  }

  const numCols = rows[0].length;

  // Calculate column widths
  const colWidths = Array(numCols).fill(0);
  for (const row of rows) {
    for (let i = 0; i < numCols; i++) {
      colWidths[i] = Math.max(colWidths[i], row[i].length);
    }
  }

  // Get alignment options (Stage 2)
  const align = options.align || Array(numCols).fill('left');

  // Determine if first row is header (Stage 3)
  const hasHeader = options.header === true;

  // Render all rows
  const renderedRows = [];
  for (const row of rows) {
    let line = '';

    for (let colIdx = 0; colIdx < numCols; colIdx++) {
      const cell = row[colIdx];
      const colWidth = colWidths[colIdx];
      const isLastCol = colIdx === numCols - 1;
      const cellAlign = align[colIdx] || 'left';

      let paddedCell;
      if (isLastCol) {
        // Last column: no trailing spaces
        if (cellAlign === 'right') {
          paddedCell = cell.padStart(colWidth, ' ');
        } else {
          paddedCell = cell;
        }
      } else {
        // Non-last columns: apply alignment and add space separator
        if (cellAlign === 'right') {
          paddedCell = cell.padStart(colWidth, ' ') + ' ';
        } else {
          paddedCell = cell.padEnd(colWidth, ' ') + ' ';
        }
      }

      line += paddedCell;
    }

    renderedRows.push(line);
  }

  // Find max line length for separator (Stage 3)
  const maxLineLength = Math.max(...renderedRows.map(l => l.length));

  // Build final output with optional header separator (Stage 3)
  const lines = [];
  for (let i = 0; i < renderedRows.length; i++) {
    lines.push(renderedRows[i]);
    if (hasHeader && i === 0) {
      lines.push('-'.repeat(maxLineLength));
    }
  }

  return lines.join('\n');
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = { renderTable, renderTableLegacy };

